Create `packages/relay/src/adapters/slack/thread-tracker.ts` with the `ThreadParticipationTracker` class.

**What to build:**

```typescript
const DEFAULT_MAX_SIZE = 1_000;
const DEFAULT_TTL_MS = 24 * 60 * 60 * 1_000; // 24 hours

export class ThreadParticipationTracker {
  private readonly entries = new Map<string, number>();
  private readonly maxSize: number;
  private readonly ttlMs: number;

  constructor(maxSize = DEFAULT_MAX_SIZE, ttlMs = DEFAULT_TTL_MS) {
    this.maxSize = maxSize;
    this.ttlMs = ttlMs;
  }

  markParticipating(channelId: string, threadTs: string): void {
    const key = `${channelId}:${threadTs}`;
    this.entries.delete(key); // refresh LRU position
    if (this.entries.size >= this.maxSize) {
      const firstKey = this.entries.keys().next().value;
      if (firstKey !== undefined) this.entries.delete(firstKey);
    }
    this.entries.set(key, Date.now());
  }

  isParticipating(channelId: string, threadTs: string): boolean {
    const key = `${channelId}:${threadTs}`;
    const timestamp = this.entries.get(key);
    if (timestamp === undefined) return false;
    if (Date.now() - timestamp > this.ttlMs) {
      this.entries.delete(key);
      return false;
    }
    return true;
  }

  clear(): void { this.entries.clear(); }
  get size(): number { return this.entries.size; }
}
```

**CRITICAL: Instance-scoped, NOT module-level.** Per `contributing/adapter-catalog.md` multiInstance rule.

**Tests in `packages/relay/src/adapters/slack/__tests__/thread-tracker.test.ts`:**

- `markParticipating()` stores entries
- `isParticipating()` returns true for tracked threads
- `isParticipating()` returns false for unknown threads
- TTL expiration removes stale entries (use `vi.useFakeTimers()`)
- LRU eviction removes oldest when at capacity (construct with small maxSize like 3)
- `clear()` removes all entries
- `size` returns correct count

**Acceptance criteria:**
- Class is instance-scoped (no module-level state)
- LRU eviction works at capacity
- TTL expiration works
- All tests pass

Add event_id-based deduplication to `handleInboundMessage()` in `packages/relay/src/adapters/slack/inbound.ts`.

**What to build:**

1. Add constants and dedup cache at module level in `inbound.ts`:
```typescript
const EVENT_DEDUP_MAX_SIZE = 500;
const EVENT_DEDUP_TTL_MS = 5 * 60 * 1_000;
interface DedupEntry { expiresAt: number; }
const seenEvents = new Map<string, DedupEntry>();
```

2. Add `InboundOptions` interface to `handleInboundMessage()` as a new optional parameter:
```typescript
export interface InboundOptions {
  eventId?: string;
  respondMode?: 'always' | 'mention-only' | 'thread-aware';
  dmPolicy?: 'open' | 'allowlist';
  dmAllowlist?: string[];
  channelOverrides?: Record<string, { enabled?: boolean; respondMode?: 'always' | 'mention-only' | 'thread-aware' }>;
  threadTracker?: ThreadParticipationTracker;
